('sql-interview-practice', 'grp-interview-readiness', 1, 'topic', NULL, NULL, NULL, 'SQL Interview Practice', 'Practice joins, windows, deduplication, cohorts, funnel queries, and performance explanations.', 'SQL Interview Practice is a concrete data engineering roadmap topic.', 'choice', 'grp-interview-readiness-topics', 2, 1, 4, 'intermediate', 80, 120, 9820, '{"source": "roadmap.sh/data-engineer", "nodeKey": "sql-interview-practice"}'::jsonb, true, true, '["Explain SQL Interview Practice", "Apply SQL Interview Practice in data engineering work"]'::jsonb, '["Can answer practical questions about SQL Interview Practice", "Can use SQL Interview Practice in a small data engineering task"]'::jsonb),
('python-data-interview-practice', 'grp-interview-readiness', 2, 'topic', NULL, NULL, NULL, 'Python Data Interview Practice', 'Practice parsing files, transforming records, writing tests, and explaining pipeline logic.', 'Python Data Interview Practice is a concrete data engineering roadmap topic.', 'choice', 'grp-interview-readiness-topics', 2, 2, 3, 'intermediate', 80, 330, 9820, '{"source": "roadmap.sh/data-engineer", "nodeKey": "python-data-interview-practice"}'::jsonb, true, true, '["Explain Python Data Interview Practice", "Apply Python Data Interview Practice in data engineering work"]'::jsonb, '["Can answer practical questions about Python Data Interview Practice", "Can use Python Data Interview Practice in a small data engineering task"]'::jsonb),
('data-engineering-system-design-interviews', 'grp-interview-readiness', 3, 'topic', NULL, NULL, NULL, 'Data Engineering System Design Interviews', 'Explain ingestion, storage, processing, quality, orchestration, observability, security, and cost tradeoffs.', 'Data Engineering System Design Interviews is a concrete data engineering roadmap topic.', 'choice', 'grp-interview-readiness-topics', 2, 3, 6, 'advanced', 80, 540, 9820, '{"source": "roadmap.sh/data-engineer", "nodeKey": "data-engineering-system-design-interviews"}'::jsonb, true, true, '["Explain Data Engineering System Design Interviews", "Apply Data Engineering System Design Interviews in data engineering work"]'::jsonb, '["Can answer practical questions about Data Engineering System Design Interviews", "Can use Data Engineering System Design Interviews in a small data engineering task"]'::jsonb),
('gate-final-review', 'ph-portfolio-career', 81, 'checkpoint', 'gate', NULL, NULL, 'Final Data Engineering Review Gate', 'Review capstone completeness, documentation, reproducibility, quality, security, and production readiness.', 'Checkpoint gates validate readiness without becoming fake phase-completion nodes.', 'checkpoint', 'ph-portfolio-career-gates', 99, 81, 1, 'intermediate', 85, 300, 10030, '{"checkpoint": true, "source": "roadmap.sh/data-engineer", "nodeKey": "gate-final-review"}'::jsonb, true, true, '["Pass Final Data Engineering Review Gate"]'::jsonb, '["Review checklist is completed", "Weak areas are identified before continuing"]'::jsonb),
('proj-capstone-data-platform', 'ph-portfolio-career', 91, 'project', NULL, NULL, NULL, 'Required Data Engineering Capstone Project', 'Build a production-style data platform: ingestion, storage, orchestration, transformation, quality tests, warehouse/lakehouse tables, observability, docs, and deployment notes.', 'Project nodes are practice-heavy. Mini-projects are optional; milestone projects are required.', 'checkpoint', 'ph-portfolio-career-projects', 100, 91, 16, 'advanced', 75, 700, 10060, '{"project": true, "optionalPractice": false, "source": "roadmap.sh/data-engineer", "nodeKey": "proj-capstone-data-platform"}'::jsonb, true, true, '["Build Required Data Engineering Capstone Project", "Produce portfolio-ready evidence"]'::jsonb, '["Working pipeline or design exists", "README explains setup and tradeoffs", "Core behavior is tested or manually verified"]'::jsonb),
('proj-portfolio-package', 'ph-portfolio-career', 92, 'project', NULL, NULL, NULL, 'Required Portfolio Final Package', 'Polish the capstone with README, diagrams, runbook, data model docs, screenshots, sample queries, and known tradeoffs.', 'Project nodes are practice-heavy. Mini-projects are optional; milestone projects are required.', 'checkpoint', 'ph-portfolio-career-projects', 100, 92, 4, 'intermediate', 75, 700, 10140, '{"project": true, "optionalPractice": false, "source": "roadmap.sh/data-engineer", "nodeKey": "proj-portfolio-package"}'::jsonb, true, true, '["Build Required Portfolio Final Package", "Produce portfolio-ready evidence"]'::jsonb, '["Working pipeline or design exists", "README explains setup and tradeoffs", "Core behavior is tested or manually verified"]'::jsonb);
